map "https://example.org/fhir/li-xinyang-interop-r4/StructureMap/ccda-medication-to-medicationstatement" = "CCDAMedicationToMedicationStatement"

uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/HITCCCDAEntry" alias CCDAEntry as source
uses "https://example.org/fhir/li-xinyang-interop-r4/StructureDefinition/hitc-canonical-medication-statement" alias MedicationStatement as target

group CCDAMedicationToMedicationStatement(source src : HITCCCDAEntry, target tgt : MedicationStatement) {
  src.entryId as v -> tgt.identifier.value = copy(v) "identifier";
  src.entryId as v -> tgt.identifier.system = evaluate('https://example.org/fhir/sid/ccda-entry') "identifierSystem";
  src.entryId as v -> tgt.status = evaluate('active') "activeStatus";
  src.code as v -> tgt.medicationCodeableConcept.coding = copy(v) "medicationCode";
  src.effectiveTime as v -> tgt.effectiveDateTime = copy(v) "effectiveTime";
  src.effectiveTime as v -> tgt.dateAsserted = copy(v) "assertedDate";
  src.subjectIdentifier as v -> tgt.subject.identifier.value = copy(v) "patientIdentifier";
  src.authorIdentifier as v -> tgt.informationSource.identifier.value = copy(v) "authorIdentifier";
}

